// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IBurnableERC20 is IERC20 {
    function burn(uint256 amount) external;
}

/**
 * @title ZexPresale
 * @dev ICO Contract handling direct POL to ZEX purchases.
 * Features an innovative 15% penalty Buyback (Refund) option for early exiters, 
 * destroying the penalized ZEX completely to enforce deflation.
 */
contract ZexPresale is Ownable, ReentrancyGuard {
    IBurnableERC20 public zexToken;

    bool public presaleActive;

    // Limits & Tracking
    uint256 public constant MAX_PRIVATE_SALE_POOL = 10_000_000 * 10**18;
    uint256 public totalZexSold;

    // Fixed Presale Rates (assuming 1 POL = $1 for simplicity)
    uint256 public constant PRIVATE_SALE_RATE = 333; // 1 POL = 333 ZEX ($0.003)
    uint256 public constant PUBLIC_SALE_RATE = 200;  // 1 POL = 200 ZEX ($0.005)

    uint256 public penaltyPercent = 15; // 15% penalty for early refunds

    struct Contribution {
        uint256 zexPurchased;
        uint256 polSpent;
    }

    mapping(address => Contribution) public contributions;

    event TokensPurchased(address indexed buyer, uint256 polAmount, uint256 zexAmount);
    event TokensRefunded(address indexed seller, uint256 zexReturned, uint256 polRefunded, uint256 zexBurned);
    event PresaleStateChanged(bool isActive);

    constructor(address _zexToken) Ownable(msg.sender) {
        zexToken = IBurnableERC20(_zexToken);
    }

    function togglePresale(bool _active) external onlyOwner {
        presaleActive = _active;
        emit PresaleStateChanged(_active);
    }

    /**
     * @dev Buy ZEX tokens directly using Native network coin (POL or MATIC)
     */
    receive() external payable {
        buyTokens();
    }

    function buyTokens() public payable nonReentrant {
        require(presaleActive, "Presale is not active");
        require(msg.value > 0, "Must send POL");

        // Determine which phase we are in (Private vs Public) based on tokens sold
        uint256 rate = (totalZexSold < MAX_PRIVATE_SALE_POOL) ? PRIVATE_SALE_RATE : PUBLIC_SALE_RATE;

        // Calculate ZEX to mint/send
        uint256 zexAmount = msg.value * rate;

        require(
            zexToken.balanceOf(address(this)) >= zexAmount,
            "Insufficient ZEX left in presale contract"
        );

        // Update tracking states BEFORE external transfer
        totalZexSold += zexAmount;
        contributions[msg.sender].zexPurchased += zexAmount;
        contributions[msg.sender].polSpent += msg.value;

        // Immediately transfer ZEX to the buyer
        require(zexToken.transfer(msg.sender, zexAmount), "Token transfer failed");

        emit TokensPurchased(msg.sender, msg.value, zexAmount);
    }

    /**
     * @dev The revolutionary 15% penalty refund/buyback feature.
     * Allows anyone to exit their ICO position before listing, but burns 15% to create deflation.
     */
    function refund(uint256 zexAmount) external nonReentrant {
        require(presaleActive, "Refunds only allowed while Presale is active");
        require(zexAmount > 0, "Amount must be > 0");
        require(contributions[msg.sender].zexPurchased >= zexAmount, "Cannot refund more than acquired here");

        // Calculate Average Price Paid: Proportion of POL to refund = (zexAmount / totalZexPurchased) * totalPolSpent
        uint256 polToRefundFull = (contributions[msg.sender].polSpent * zexAmount) / contributions[msg.sender].zexPurchased;

        // Calculate 15% penalty on the POL and the ZEX
        uint256 polToRefund = (polToRefundFull * (100 - penaltyPercent)) / 100;
        uint256 zexToBurn = (zexAmount * penaltyPercent) / 100;

        // Update user state BEFORE external calls
        contributions[msg.sender].zexPurchased -= zexAmount;
        contributions[msg.sender].polSpent -= polToRefundFull;

        // Substract from total sold so the remaining unburned part can be bought by others
        totalZexSold -= zexAmount;

        // The user must have approved this contract to take the ZEX back
        require(zexToken.transferFrom(msg.sender, address(this), zexAmount), "Failed to return ZEX. Ensure allowance is set.");

        // Burn the penalty portion natively from the smart contract balance (Kara Delik / Blackhole)
        zexToken.burn(zexToBurn);

        // Send the POL refund back to the user
        (bool success, ) = payable(msg.sender).call{value: polToRefund}("");
        require(success, "POL refund failed");

        emit TokensRefunded(msg.sender, zexAmount, polToRefund, zexToBurn);
    }

    /**
     * @dev Allows the owner to withdraw the collected POL funds (the 100% minus refunds, and the 15% penalty POL margins remain in balance).
     */
    function withdrawFunds() external onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "No funds to withdraw");

        (bool success, ) = payable(owner()).call{value: balance}("");
        require(success, "Fund withdrawal failed");
    }

    /**
     * @dev Withdraw unsold tokens (or remaining after presale concludes).
     */
    function retrieveUnsoldTokens() external onlyOwner {
        uint256 balance = zexToken.balanceOf(address(this));
        require(balance > 0, "No ZEX left");
        require(zexToken.transfer(owner(), balance), "Token retrieval failed");
    }
}

contracts/ZexToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title ZexToken
 * @dev ERC20 Token for the ZexAI Ecosystem.
 * Used for generative AI API payments and utility within the platform.
 */
contract ZexToken is ERC20, ERC20Burnable, Ownable {
    uint256 public constant MAX_SUPPLY = 1_000_000_000 * 10**18;
    uint256 public constant MIN_SUPPLY = 500_000_000 * 10**18; // Cease deflationary burn below this
    
    // V3 Base Transfer Tax: 5% (50 basis points out of 1000)
    uint256 public transferFeeBasisPoints = 50; 
    mapping(address => bool) public isExcludedFromFee;

    // V3 Anti-Whale max tx amount (1% of MAX_SUPPLY)
    uint256 public maxTxAmount = 10_000_000 * 10**18;

    // V3 Staking Rewards / Auto-Liquidity Wallet
    address public stakingRewardWallet;

    constructor(address initialOwner) ERC20("ZexToken", "ZEX") Ownable(initialOwner) {
        // Exclude owner/deployer from fee
        isExcludedFromFee[initialOwner] = true;
        isExcludedFromFee[address(this)] = true;
        
        _mint(initialOwner, MAX_SUPPLY);
    }

    function setExcludeFromFee(address account, bool excluded) external onlyOwner {
        isExcludedFromFee[account] = excluded;
    }

    function setTransferFee(uint256 basisPoints) external onlyOwner {
        require(basisPoints <= 100, "Tax cannot exceed 10%");
        transferFeeBasisPoints = basisPoints;
    }

    function setMaxTxAmount(uint256 amount) external onlyOwner {
        maxTxAmount = amount;
    }

    function setStakingRewardWallet(address wallet) external onlyOwner {
        stakingRewardWallet = wallet;
    }

    // Dynamic fee calculation based on shrinking supply
    function getCurrentFeeBasisPoints() public view returns (uint256) {
        uint256 currentSupply = totalSupply();
        if (currentSupply <= MIN_SUPPLY) {
            return 0; // No deflationary fee once min supply is reached
        } else if (currentSupply <= 600_000_000 * 10**18) {
            return 10; // 1% (10 basis points)
        } else if (currentSupply <= 750_000_000 * 10**18) {
            return 30; // 3% (30 basis points)
        } else {
            return transferFeeBasisPoints; // Base fee (usually 50 = 5%)
        }
    }

    // Override the core openzeppelin v5 _update function to apply dynamic deflationary & reward split fee
    function _update(address from, address to, uint256 value) internal virtual override {
        // If minting, burning, or either sender/receiver is whitelisted, do normal transfer
        if (from == address(0) || to == address(0) || isExcludedFromFee[from] || isExcludedFromFee[to]) {
            super._update(from, to, value);
        } else {
            // Anti-Whale Check
            require(value <= maxTxAmount, "Transfer amount exceeds max tx limit");

            // Dynamic Fee Calculation
            uint256 currentFeeBps = getCurrentFeeBasisPoints();
            
            if (currentFeeBps > 0) {
                uint256 feeAmount = (value * currentFeeBps) / 1000;
                uint256 sendAmount = value - feeAmount;
                
                // Split fee: Half to burn, half to staking rewards
                uint256 burnAmount = feeAmount / 2;
                uint256 rewardAmount = feeAmount - burnAmount;
                
                // Burn the tokens from sender
                super._update(from, address(0), burnAmount);
                
                // Send to staking rewards wallet
                if (stakingRewardWallet != address(0)) {
                    super._update(from, stakingRewardWallet, rewardAmount);
                } else {
                    // If no reward wallet is set yet, we just burn the other half too to ensure no unbacked tokens
                    super._update(from, address(0), rewardAmount);
                }
                
                // Transfer the remaining amount to receiver
                super._update(from, to, sendAmount);
            } else {
                // Transfer without fee if supply went under MIN_SUPPLY
                super._update(from, to, value);
            }
        }
    }
}

contracts/ZexVesting.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title ZexVesting
 * @dev Highly secure and transparent vesting contract for ZexAI Ecosystem.
 * Allows tracking linear unlocks after a cliff period for Team, Advisors, and Marketing.
 */
contract ZexVesting is Ownable, ReentrancyGuard {
    IERC20 public immutable zexToken;

    struct VestingSchedule {
        uint256 totalAmount;
        uint256 amountReleased;
        uint256 startTime;
        uint256 cliffDuration;
        uint256 vestingDuration;
        bool isRevocable;
        bool revoked;
    }

    mapping(address => VestingSchedule) public vestingSchedules;
    uint256 public totalVestingAmount;

    event VestingScheduleCreated(
        address indexed beneficiary,
        uint256 amount,
        uint256 startTime,
        uint256 cliffDuration,
        uint256 vestingDuration
    );
    event TokensReleased(address indexed beneficiary, uint256 amount);
    event VestingRevoked(address indexed beneficiary, uint256 amountRefunded);

    constructor(address _zexToken) Ownable(msg.sender) {
        require(_zexToken != address(0), "Invalid token address");
        zexToken = IERC20(_zexToken);
    }

    /**
     * @dev Creates a new vesting schedule for a beneficiary.
     */
    function createVestingSchedule(
        address beneficiary,
        uint256 amount,
        uint256 startTime,
        uint256 cliffDuration,
        uint256 vestingDuration,
        bool isRevocable
    ) external onlyOwner {
        require(beneficiary != address(0), "Invalid beneficiary");
        require(amount > 0, "Amount must be > 0");
        require(vestingSchedules[beneficiary].totalAmount == 0, "Schedule already exists");
        require(vestingDuration > 0, "Vesting duration must be > 0");

        vestingSchedules[beneficiary] = VestingSchedule({
            totalAmount: amount,
            amountReleased: 0,
            startTime: startTime,
            cliffDuration: cliffDuration,
            vestingDuration: vestingDuration,
            isRevocable: isRevocable,
            revoked: false
        });

        totalVestingAmount += amount;

        // Ensure the contract actually holds enough tokens to cover this new schedule
        require(
            zexToken.balanceOf(address(this)) >= totalVestingAmount,
            "Contract does not have enough tokens to back this schedule"
        );

        emit VestingScheduleCreated(beneficiary, amount, startTime, cliffDuration, vestingDuration);
    }

    /**
     * @dev Calculates the vested amount that has been unlocked so far.
     */
    function vestedAmount(address beneficiary) public view returns (uint256) {
        VestingSchedule memory schedule = vestingSchedules[beneficiary];

        if (schedule.totalAmount == 0) {
            return 0; // No schedule
        }

        if (block.timestamp < schedule.startTime + schedule.cliffDuration) {
            return 0; // Still in cliff
        } else if (
            block.timestamp >= schedule.startTime + schedule.cliffDuration + schedule.vestingDuration || 
            schedule.revoked
        ) {
            return schedule.totalAmount; // Fully vested or revoked (capped at what was vested before revocation)
        } else {
            // Linear vesting
            uint256 timePassed = block.timestamp - (schedule.startTime + schedule.cliffDuration);
            return (schedule.totalAmount * timePassed) / schedule.vestingDuration;
        }
    }

    /**
     * @dev Releases the unlocked tokens to the beneficiary.
     */
    function release() external nonReentrant {
        VestingSchedule storage schedule = vestingSchedules[msg.sender];
        require(schedule.totalAmount > 0, "No vesting schedule found");
        require(!schedule.revoked, "Vesting schedule revoked");

        uint256 vested = vestedAmount(msg.sender);
        uint256 unreleased = vested - schedule.amountReleased;

        require(unreleased > 0, "No tokens are due to be released");

        schedule.amountReleased += unreleased;
        totalVestingAmount -= unreleased;

        require(zexToken.transfer(msg.sender, unreleased), "Token transfer failed");

        emit TokensReleased(msg.sender, unreleased);
    }

    /**
     * @dev Revokes the vesting schedule, retaining unvested tokens for the owner.
     */
    function revoke(address beneficiary) external onlyOwner {
        VestingSchedule storage schedule = vestingSchedules[beneficiary];
        require(schedule.totalAmount > 0, "No vesting schedule found");
        require(schedule.isRevocable, "Vesting is not revocable");
        require(!schedule.revoked, "Already revoked");

        uint256 vested = vestedAmount(beneficiary);
        uint256 unreleased = vested - schedule.amountReleased;
        uint256 refund = schedule.totalAmount - vested;

        schedule.revoked = true;
        // The total amount is adjusted to what they actually earned
        schedule.totalAmount = vested;

        // Remove unvested part from total liabilities
        totalVestingAmount -= refund;

        // Refund unvested tokens to the owner
        require(zexToken.transfer(owner(), refund), "Token refund transfer failed");

        emit VestingRevoked(beneficiary, refund);
    }
}

